encodeMove({ x, y, z, yaw, pitch }) {
  const chunk = this.worldToChunk(x, z);
  const local = this.globalToLocalChunk(chunk.x, chunk.z);
  const offsetX = x - chunk.x * this.chunkSize;
  const offsetZ = z - chunk.z * this.chunkSize;
  const bytes = new Uint8Array(MOVE_SIZE);
  const view = new DataView(bytes.buffer);
  view.setUint8(0, MSG_MOVE);
  view.setUint8(1, clampByte(local.x));
  view.setUint8(2, clampByte(local.z));
  view.setUint16(3, clampU16(Math.round(offsetX * this.positionPrecision)), true);
  view.setUint16(5, clampU16(Math.round(y * this.positionPrecision)), true);
  view.setUint16(7, clampU16(Math.round(offsetZ * this.positionPrecision)), true);
  view.setUint8(9, encodeYaw(yaw));
  view.setInt8(10, encodePitch(pitch));
  view.setUint16(11, ++this.clientTick & 0xffff, true);
  return bytes;
}

void handle_move(Ws<SSL> *ws, GuardianState &state, std::string_view message) {
  Player *player = ws->getUserData()->player;
  if (!player || !player->connected || !state.is_active_player(player)) {
    close_with_error(ws, ERROR_NOT_HELLO);
    return;
  }
  Move move;
  if (!decode_move(message, move)) {
    close_with_error(ws, ERROR_BAD_PAYLOAD_LENGTH);
    return;
  }
  uint64_t t = now_ms();
  if (!rate_limit_allow(t, player->move_window_ms, player->move_count, state.config().client_move_rate_limit_per_sec)) {
    send_error(ws, ERROR_RATE_LIMIT);
    return;
  }
  int32_t new_chunk_x = 0;
  int32_t new_chunk_z = 0;
  if (!state.local_to_global(move.local_chunk_x, move.local_chunk_z, new_chunk_x, new_chunk_z)) {
    state.add_log("Player #" + std::to_string(player->local_player_id) + " moved out of Guardian range");
    close_with_error(ws, ERROR_OUT_OF_RANGE);
    return;
  }
